parameters.jsCode:
const body = $json.body ?? $json;
const allowed = Array.isArray(body.allowed_actions) ? body.allowed_actions : [];
const context = body.context && typeof body.context === 'object' ? body.context : {};
const instruction = String(body.instruction ?? body.chatInput ?? body.message ?? '').trim();

return [{
  json: {
    source: body.source ?? 'manual',
    organization_id: body.organization_id,
    user_id: body.user_id,
    role: body.role ?? 'employee',
    department: body.department ?? null,
    instruction,
    context,
    allowed_actions: allowed,
    can_create_task: allowed.includes('create_task'),
    can_suggest_task: allowed.includes('suggest_task') || allowed.length === 0,
    received_at: new Date().toISOString()
  }
}];

const previous = $('Normalize Automation Payload').first().json;
const raw = $json.output ?? $json.text ?? $json.message ?? $json;
let parsed;

try {
  parsed = typeof raw === 'string' ? JSON.parse(raw.replace(/^```json\s*/i, '').replace(/```$/i, '').trim()) : raw;
} catch (error) {
  parsed = {
    status: 'success',
    summary: typeof raw === 'string' ? raw : 'AI automation completed, but response was not structured JSON.',
    suggestions: [],
    recommended_actions: [],
    logs: ['AI response required fallback parsing.'],
    errors: []
  };
}

const actions = Array.isArray(parsed.recommended_actions) ? parsed.recommended_actions : [];
const normalizedActions = actions
  .filter(action => action && action.type === 'create_task' && action.title)
  .map(action => ({
    type: 'create_task',
    title: String(action.title).trim(),
    description: action.description ? String(action.description) : null,
    priority: ['low', 'medium', 'high', 'urgent'].includes(action.priority) ? action.priority : 'medium',
    assignee: action.assignee ?? null,
    assignee_id: action.assignee_id ?? null,
    due_date: action.due_date ?? null,
    department: action.department ?? previous.department ?? null,
    requires_approval: action.requires_approval !== false || !previous.can_create_task,
    reason: action.reason ?? 'AI identified this as a task from the manual request.'
  }));

return [{
  json: {
    ...previous,
    status: parsed.status ?? 'success',
    summary: parsed.summary ?? 'AI automation request processed.',
    suggestions: Array.isArray(parsed.suggestions) ? parsed.suggestions : [],
    recommended_actions: normalizedActions,
    logs: Array.isArray(parsed.logs) ? parsed.logs : [],
    errors: Array.isArray(parsed.errors) ? parsed.errors : [],
    should_create_direct_task: normalizedActions.some(action => action.requires_approval === false),
    should_create_suggestion: normalizedActions.some(action => action.requires_approval !== false)
  }
}];

parameters.responseBody:
={{ {
  status: $json.status,
  summary: $json.summary,
  suggestions: $json.suggestions,
  recommended_actions: $json.recommended_actions,
  logs: $json.logs.concat(['n8n workflow processed manual task automation.']),
  errors: $json.errors
} }}
